mapper.select:
SELECT BASE.NICKNAME, BASE.TOTAL_EXP AS EXP, BASE.POINT, BASE.CURRENT_LEVEL, NVL( ( SELECT LR.MIN_EXP FROM LQ_LEVEL_RANGE LR WHERE LR.LEVEL_NO = BASE.CURRENT_LEVEL AND ROWNUM = 1 ), (BASE.CURRENT_LEVEL - 1) * 500 ) AS CURRENT_LEVEL_MIN_EXP, BASE.CURRENT_LEVEL + 1 AS NEXT_LEVEL, NVL( ( SELECT LR.MIN_EXP FROM LQ_LEVEL_RANGE LR WHERE LR.LEVEL_NO = BASE.CURRENT_LEVEL + 1 AND ROWNUM = 1 ), NVL( ( SELECT LR.MIN_EXP FROM LQ_LEVEL_RANGE LR WHERE LR.LEVEL_NO = BASE.CURRENT_LEVEL AND ROWNUM = 1 ), (BASE.CURRENT_LEVEL - 1) * 500 ) + 500 ) AS NEXT_LEVEL_MIN_EXP, ( SELECT T.GRADE_NAME FROM ( SELECT GR.GRADE_NAME, GR.MIN_LEVEL FROM LQ_GRADE_RANGE GR WHERE BASE.CURRENT_LEVEL >= NVL(GR.MIN_LEVEL, 1) AND (GR.MAX_LEVEL IS NULL OR BASE.CURRENT_LEVEL <= GR.MAX_LEVEL) ORDER BY NVL(GR.MIN_LEVEL, 0) DESC ) T WHERE ROWNUM = 1 ) AS CURRENT_GRADE_NAME, ( SELECT T.MIN_LEVEL FROM ( SELECT GR.MIN_LEVEL FROM LQ_GRADE_RANGE GR WHERE BASE.CURRENT_LEVEL >= NVL(GR.MIN_LEVEL, 1) AND (GR.MAX_LEVEL IS NULL OR BASE.CURRENT_LEVEL <= GR.MAX_LEVEL) ORDER BY NVL(GR.MIN_LEVEL, 0) DESC ) T WHERE ROWNUM = 1 ) AS CURRENT_GRADE_MIN_LEVEL, ( SELECT T.MAX_LEVEL FROM ( SELECT GR.MAX_LEVEL, GR.MIN_LEVEL FROM LQ_GRADE_RANGE GR WHERE BASE.CURRENT_LEVEL >= NVL(GR.MIN_LEVEL, 1) AND (GR.MAX_LEVEL IS NULL OR BASE.CURRENT_LEVEL <= GR.MAX_LEVEL) ORDER BY NVL(GR.MIN_LEVEL, 0) DESC ) T WHERE ROWNUM = 1 ) AS CURRENT_GRADE_MAX_LEVEL, ( SELECT T.GRADE_NAME FROM ( SELECT GR.GRADE_NAME, GR.MIN_LEVEL FROM LQ_GRADE_RANGE GR WHERE NVL(GR.MIN_LEVEL, 1) > BASE.CURRENT_LEVEL ORDER BY NVL(GR.MIN_LEVEL, 999999) ASC ) T WHERE ROWNUM = 1 ) AS NEXT_GRADE_NAME, ( SELECT T.MIN_LEVEL FROM ( SELECT GR.MIN_LEVEL FROM LQ_GRADE_RANGE GR WHERE NVL(GR.MIN_LEVEL, 1) > BASE.CURRENT_LEVEL ORDER BY NVL(GR.MIN_LEVEL, 999999) ASC ) T WHERE ROWNUM = 1 ) AS NEXT_GRADE_MIN_LEVEL FROM ( SELECT U.NICKNAME, NVL(U.EXP, 0) AS TOTAL_EXP, NVL(U.POINT, 0) AS POINT, NVL( ( SELECT MAX(LR.LEVEL_NO) FROM LQ_LEVEL_RANGE LR WHERE NVL(U.EXP, 0) >= NVL(LR.MIN_EXP, 0) AND (LR.MAX_EXP IS NULL OR NVL(U.EXP, 0) <= LR.MAX_EXP) ), FLOOR(NVL(U.EXP, 0) / 500) + 1 ) AS CURRENT_LEVEL FROM LQ_USER U WHERE U.STATUS = 'ACTIVE'
AND U.NICKNAME = #{_parameter}
ORDER BY NVL(U.EXP, 0) DESC, U.USER_ID ASC ) BASE WHERE ROWNUM = 1

SELECT RE.EXCHANGE_ID, RI.NAME, NVL(NULLIF(TRIM(RI.DESCRIPTION), ''), '리워드 상점') AS STORE, RE.STATUS, RE.EXPIRED_AT, CASE WHEN RE.EXPIRED_AT IS NULL THEN NULL ELSE TRUNC(RE.EXPIRED_AT) - TRUNC(SYSDATE) END AS DAYS_LEFT FROM LQ_REWARD_EXCHANGE RE INNER JOIN LQ_USER U ON U.USER_ID = RE.USER_ID INNER JOIN LQ_REWARD_ITEM RI ON RI.REWARD_ITEM_ID = RE.REWARD_ITEM_ID WHERE U.STATUS = 'ACTIVE'
AND U.NICKNAME = #{_parameter}
AND (RE.STATUS IS NULL OR UPPER(RE.STATUS) NOT IN ('USED', 'EXPIRED')) AND (RE.EXPIRED_AT IS NULL OR TRUNC(RE.EXPIRED_AT) >= TRUNC(SYSDATE) ) ORDER BY NVL(RE.EXPIRED_AT, TO_DATE('2999-12-31', 'YYYY-MM-DD')) ASC, RE.EXCHANGED_AT DESC
